#include <stdio.h>
#include <stdlib.h>

int main() {
    int n;
    while (scanf("%d", &n) == 1 && n != 0) {
        int *p = (int*)malloc((n + 1) * sizeof(int));
        for (int i = 1; i <= n; ++i) {
            scanf("%d", &p[i]);
        }
        int ambiguous = 1;
        for (int i = 1; i <= n && ambiguous; ++i) {
            if (p[p[i]] != i) ambiguous = 0;
        }
        printf(ambiguous ? "ambiguous\n" : "not ambiguous\n");
        free(p);
    }
    return 0;
}

