#!/usr/bin/env python3
import sys

def main():
    data = sys.stdin.read().strip().split()
    idx = 0
    out = []
    while idx < len(data):
        n = int(data[idx]); idx += 1
        if n == 0:
            break
        p = [0] + list(map(int, data[idx:idx + n])); idx += n
        ok = True
        for i in range(1, n + 1):
            if p[p[i]] != i:
                ok = False
                break
        out.append('ambiguous' if ok else 'not ambiguous')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

