  const n = Number(tokens[idx++]);
  if (n === 0) break;
  const p = new Array(n + 1);
  for (let i = 1; i <= n; i++) {
    p[i] = Number(tokens[idx++]);
  }
  let ok = true;
  for (let i = 1; i <= n && ok; i++) {
    if (p[p[i]] !== i) ok = false;
  }
  results.push(ok ? 'ambiguous' : 'not ambiguous');
}
